request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?modelName ?model ?msgName ?created ?orgName WHERE {
  ?msg a bboExt:Message ;
       bbo:name ?msgName ;
       tai:belongsTo ?choreo .
  FILTER(CONTAINS(LCASE(STR(?msgName)), LCASE("Auktiosnhaus")))

  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .
  ?model a bboExt:Model ;
         bbo:name ?modelName ;
         tai:modelCreated ?created ;
         tai:belongsTo ?org .
  OPTIONAL { ?org rdfs:label ?orgName . }
}
ORDER BY ?created
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?modelName ?model ?msgName ?created ?orgName WHERE {
  ?msg a bboExt:Message ;
       bbo:name ?msgName ;
       tai:belongsTo ?choreo .
  FILTER(
    CONTAINS(LCASE(STR(?msgName)), LCASE("auktio")) ||
    CONTAINS(LCASE(STR(?msgName)), LCASE("auktion"))
  )

  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?model a bboExt:Model ;
         bbo:name ?modelName ;
         tai:modelCreated ?created ;
         tai:belongsTo ?org .
  OPTIONAL { ?org rdfs:label ?orgName . }
}
ORDER BY ?created
LIMIT 25
